package crypto

import (
	"crypto/rand"
	"errors"
	"github.com/decred/dcrd/crypto/secp256k1"
)

// GeneratePrivateKey creates a new private key of the specified type and size.
// If entropy is provided, it uses it to generate the key; otherwise, it uses crypto/rand.
func GeneratePrivateKey(keyType string, size int, entropy io.Reader) (interface{}, error) {
	switch keyType {
	case "secp256k1":
		if entropy == nil {
			entropy = rand.Reader
		}
		keyBytes := make([]byte, size)
		_, err := io.ReadFull(entropy, keyBytes)
		if err != nil {
			return nil, err
		}
		privateKey, err := secp256k1.PrivKeyFromBytes(keyBytes)
		if err != nil {
			return nil, err
		}
		return privateKey, nil
	// Add support for other key types as needed
	default:
		return nil, errors.New("unsupported key type")
	}
}
