package main

import (
	"fmt"
)

type VM struct {
	Metrics  string
	Regexps  string
	Strings  string
	Disasm   []string
	Bytecode []byte
}

func (v *VM) String() string {
	var sb strings.Builder
	sb.WriteString(fmt.Sprintf("Metrics: %s\n", v.Metrics))
	sb.WriteString(fmt.Sprintf("Regexps: %s\n", v.Regexps))
	sb.WriteString(fmt.Sprintf("Strings: %s\n", v.Strings))
	sb.WriteString("Disasm:\n")
	for _, line := range v.Disasm {
		sb.WriteString(fmt.Sprintf("  %s\n", line))
	}
	sb.WriteString("Bytecode:\n")
	for i := 0; i < len(v.Bytecode); i++ {
		if i > 0 && i%16 == 0 {
			sb.WriteString("\n")
		}
		sb.WriteString(fmt.Sprintf("%02X ", v.Bytecode[i]))
	}
	return sb.String()
}
