  var selectedItems = element.querySelectorAll('.selected-item');
  var filterText = searchInput ? searchInput.value.toLowerCase() : '';

  dropdownList.innerHTML = '';

  selectedItems.forEach(function(item) {
    var clone = item.cloneNode(true);
    dropdownList.appendChild(clone);
  });

  if (dropdownList.children.length === 0) {
    var emptyOption = document.createElement('li');
    emptyOption.textContent = 'No options selected';
    emptyOption.classList.add('empty-option');
    dropdownList.appendChild(emptyOption);
  } else {
    Array.from(dropdownList.children).forEach(function(option) {
      if (filterText && !option.textContent.toLowerCase().includes(filterText)) {
        option.style.display = 'none';
      } else {
        option.style.display = '';
      }
    });
  }
}
