The function should be called when a button is clicked. The sliding element should start from the bottom of the page and move upwards to reveal its content. After 3 seconds, the element should smoothly slide back down and disappear.

```javascript
// HTML structure for reference
// <button id="showButton">Show Message</button>
// <div id="messageBox" style="display:none; position:fixed; bottom:0; width:100%; background-color:#f0f0f0; padding:10px; text-align:center;">
//   This is a sliding message.
// </div>

function showMessage() {
  var messageBox = document.getElementById('messageBox');
  messageBox.style.display = 'block';
  messageBox.style.bottom = '0';

  setTimeout(function() {
    var slideUpInterval = setInterval(function() {
      var currentBottom = parseInt(messageBox.style.bottom);
      if (currentBottom > 0) {
        messageBox.style.bottom = (currentBottom - 5) + 'px';
      } else {
        clearInterval(slideUpInterval);
        messageBox.style.display = 'none';
      }
    }, 20);
  }, 3000);
}
