```javascript
function updateGrade(studentName, courseName, gradeType, newGrade) {
    var table = document.getElementById('gradesTable');
    var rows = table.getElementsByTagName('tr');

    for (var i = 0; i < rows.length; i++) {
        var cells = rows[i].getElementsByTagName('td');
        if (cells.length > 1) {
            var student = cells[0].textContent;
            var course = cells[1].textContent;
            if (student === studentName && course === courseName) {
                if (gradeType === 'text') {
                    cells[2].textContent = newGrade;
                } else if (gradeType === 'image') {
                    cells[2].innerHTML = '<img src="' + newGrade + '" alt="Grade Image">';
                }
                break;
            }
        }
    }
}
