Generation:
The plugin should have the following functionalities:
1. When called with no arguments, it toggles the badge visibility.
2. When called with a string argument, it updates the text of the badge and toggles its visibility.
3. It accepts an options object with properties:
   - `inline`: A boolean indicating whether the badge should be styled as inline or overlay.
   - `text`: A string for the initial badge text (optional, defaults to "New").

```javascript
(function($) {
    $.fn.badge = function(options) {
        var settings = $.extend({
            inline: false,
            text: 'New'
        }, options);

        return this.each(function() {
            var $this = $(this);
            var $badge = $this.find('.badge');

            if (!$badge.length) {
                $badge = $('<span class="badge"></span>').appendTo($this);
                $badge.text(settings.text);
            }

            if (typeof options === 'undefined') {
                $badge.toggle();
            } else if (typeof options === 'string') {
                $badge.text(options).toggle();
            }

            if (settings.inline) {
                $badge.addClass('inline-badge');
            } else {
                $badge.removeClass('inline-badge');
            }
        });
    };
})(jQuery);
