The function should also manage message visibility and update unread counts based on certain conditions.

```javascript
function displayMessage(message, chatId, userId) {
  const { content, type, mentions } = message;
  const chat = document.getElementById(`chat-${chatId}`);
  const chatList = chat.querySelector('.chat-list');
  const messageItem = document.createElement('div');
  messageItem.className = 'message-item';

  if (type === 'text') {
    const textNode = document.createTextNode(content);
    messageItem.appendChild(textNode);
  } else if (type === 'image') {
    const img = document.createElement('img');
    img.src = content;
    img.alt = 'chat image';
    messageItem.appendChild(img);
  }

  if (mentions && mentions.includes(userId)) {
    messageItem.classList.add('highlight');
  }

  chatList.appendChild(messageItem);
  chat.scrollTop = chat.scrollHeight; // Auto-scroll to bottom

  if (message.sender !== userId) {
    const chatHeader = document.querySelector(`.chat-header[data-chat-id="${chatId}"]`);
    const unreadCount = chatHeader.querySelector('.unread-count');
    if (unreadCount) {
      const currentCount = parseInt(unreadCount.textContent, 10) || 0;
      unreadCount.textContent = currentCount + 1;
    }
  }
}
