<script>
$(document).ready(function() {
    // Initial contact list
    var contacts = ['Alice Johnson', 'Bob Smith', 'Charlie Brown', 'David Davis'];

    // Event handler for input field changes
    $('#nameInput').on('input', function() {
        var filterName = $(this).val().toLowerCase();
        var filteredContacts = contacts.filter(function(contact) {
            return contact.toLowerCase().startsWith(filterName);
        });

        // Clear existing contacts and append filtered contacts
        $('#contactList').empty();
        filteredContacts.forEach(function(contact) {
            $('#contactList').append($('<li>').text(contact));
        });
