The function should manage the state of checkboxes and handle click events on table rows and their child elements. Additionally, it should prevent the default action for certain elements like dropdowns and checkboxes.

```javascript
function handleTableInteractions() {
  const rows = document.querySelectorAll('.custom-table-row');
  rows.forEach(row => {
    row.addEventListener('click', (e) => {
      if (e.target.tagName === 'INPUT' || e.target.tagName === 'SELECT') {
        e.preventDefault();
      }
      const checkbox = row.querySelector('.row-checkbox');
      if (checkbox) {
        checkbox.checked = !checkbox.checked;
      }
      const details = row.querySelector('.details');
      if (details) {
        details.style.display = details.style.display === 'block' ? 'none' : 'block';
      }
      e.stopPropagation();
    });
  });
}
```

