```javascript
function updatePreview() {
  var selectedType = $('#inputType').val();
  var $inputField = $('#previewInput');
  var $option = $('#previewOption');
  var $previewText = $('#previewText');

  if (selectedType === 'text') {
    var inputValue = $inputField.val();
    $option.val(inputValue);
    $previewText.text(inputValue);
  } else if (selectedType === 'image') {
    $option.val('img');
    $previewText.text('Image');
  }
  $inputField.val('');
}
