    return {'can_set_preference': True}

@app.route('/set_preference', methods=['POST'])
@requires_auth
def set_preference():
    try:
        key = request.json.get('key')
        value = request.json.get('value')
        username = request.authorization.username

        if not key or not value:
            return jsonify({'error': 'Key and value are required'}), 400

        permissions = get_user_permissions(username)
        if not permissions.get('can_set_preference'):
            return jsonify({'error': 'Permission denied'}), 403

        conn = sqlite3.connect('preferences.db')
        cursor = conn.cursor()
        cursor.execute("INSERT INTO preferences (user, key, value) VALUES (?, ?, ?)", (username, key, value))
        conn.commit()
        conn.close()

        return jsonify({'message': 'Preference set successfully'}), 200

    except Exception as e:
        return jsonify({'error': str(e)}), 500
