const { execSync } = require('child_process');

function runCommandSync(options) {
  const { command, stdin, inputFile, outputFile, errorFile } = options;
  let commandWithInput = command;

  if (inputFile) {
    commandWithInput += ` < ${inputFile}`;
  }

  if (outputFile) {
    commandWithInput += ` > ${outputFile}`;
  }

  try {
    let output = execSync(commandWithInput, { input: stdin });
    if (errorFile) {
      fs.writeFileSync(errorFile, '');
    }
    return { stdout: output.toString(), stderr: '' };
  } catch (error) {
    if (outputFile) {
      fs.writeFileSync(outputFile, '');
    }
    return { stdout: '', stderr: error.stderr.toString() };
  }
}
