const { spawn } = require('child_process');

async function rsync(source, destination, options = {}) {
  // Construct the rsync command with options
  const rsyncCommand = ['rsync', ...Object.keys(options).map(key => `--${key}=${options[key]}`), source, destination];

  return new Promise((resolve, reject) => {
    const rsyncProcess = spawn(rsyncCommand.join(' '), { shell: true });

    rsyncProcess.stdout.on('data', (data) => {
      console.log(`rsync stdout: ${data}`);
    });

    rsyncProcess.stderr.on('data', (data) => {
      console.error(`rsync stderr: ${data}`);
    });

    rsyncProcess.on('close', (code) => {
      if (code === 0) {
        resolve();
      } else {
        reject(new Error(`rsync process exited with code ${code}`));
      }
    });
  });
}
