The component should accept props `repo`, `lines`, and `matches`. It should render each line, highlighting matched terms with `<mark>` tags and including a link to the specific line in the repository. Each line number should be clickable to scroll to that line.

```jsx
import React from 'react';

const MatchedLines = ({ repo, lines, matches }) => {
  const scrollToLine = (lineNumber) => {
    const element = document.getElementById(`line-${lineNumber}`);
    element.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <div className="matched-lines">
      {lines.map((line, index) => {
        const lineNumber = index + 1;
        const markedLine = matches.reduce((acc, match) => {
          const regex = new RegExp(`(${match})`, 'gi');
          return acc.replace(regex, '<mark>$1</mark>');
        }, line);

        return (
          <div key={lineNumber} id={`line-${lineNumber}`}>
            <a href="#" onClick={() => scrollToLine(lineNumber)}>
              {lineNumber}
            </a>
            :
            <span dangerouslySetInnerHTML={{ __html: markedLine }} />
            <a href={`/source/${repo}/${lineNumber}`}>
              [source]
            </a>
          </div>
        );
      })}
    </div>
  );
};

export default MatchedLines;
