)

type Record struct {
	ID   int
	Name string
}

func fetchRecord(w http.ResponseWriter, r *http.Request) {
	// Retrieve parameters from the request
	id := r.URL.Query().Get("id")
	name := r.URL.Query().Get("name")

	// Connect to the MySQL database
	db, err := sql.Open("mysql", "user:password@tcp(127.0.0.1:3306)/dbname")
	if err != nil {
		http.Error(w, "Failed to connect to database", http.StatusInternalServerError)
		log.Println("Error opening database:", err)
		return
	}
	defer db.Close()

	// Prepare SQL statement to avoid SQL injection
	stmt, err := db.Prepare("SELECT id, name FROM records WHERE id = ? AND name = ?")
	if err != nil {
		http.Error(w, "Database preparation error", http.StatusInternalServerError)
		log.Println("Error preparing statement:", err)
		return
	}
	defer stmt.Close()

	// Execute the query
	var rec Record
	err = stmt.QueryRow(id, name).Scan(&rec.ID, &rec.Name)
	if err != nil {
		if err == sql.ErrNoRows {
			http.Error(w, "No record found", http.StatusNotFound)
		} else {
			http.Error(w, "Failed to fetch record", http.StatusInternalServerError)
			log.Println("Error fetching record:", err)
		}
		return
	}

	// Respond with the fetched record
	fmt.Fprintf(w, "Record Found: ID=%d, Name=%s", rec.ID, rec.Name)
}

func main() {
	http.HandleFunc("/fetch", fetchRecord)
	log.Println("Starting server at port 8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal("ListenAndServe:", err)
	}
}
