    _id: id
  }, function(err, user){
    if (err){
      return callback(err);
    }

    if (!user){
      return callback({
        message: "User not found."
      });
    }

    if (user.team){
      return callback({
        message: "You are already on a team."
      });
    }

    Team.findOne({
      name: code
    }, function(err, team){
      if (err){
        return callback(err);
      }

      if (!team){
        return callback({
          message: "Team not found."
        });
      }

      if (team.members.length >= 5){
        return callback({
          message: "Team is full."
        });
      }

      team.members.push(id);
      team.save(function(err){
        if (err){
          return callback(err);
        }

        user.team = team._id;
        user.save(function(err){
          if (err){
            return callback(err);
          }

          return callback(null, team);
        });
      });
    });
  });
};

