  taxon_ids = filter_by_project(taxon_ids, filters[:project_id]) if filters[:project_id]
  taxon_ids = Set.new(taxon_ids)

  return matching_taxa.select { |taxon| taxon_ids.include? taxon["taxid"] }
end

