            const xml = '<person><name>John</name><age>30</age></person>';
            const expected = { person: { name: 'John', age: '30' } };
            expect(ConfigParser.parseXML(xml)).to.deep.equal(expected);
        });
        it('should throw an error for invalid XML', function() {
