// Function to parse URL parameters into a nested object
function parseUrlParams(queryString) {
  const params = {};
  const pairs = queryString.split('&');
  pairs.forEach(pair => {
    const [key, value] = pair.split('=');
    const keys = key.split('.');
    let current = params;
    keys.forEach((k, index) => {
      if (index === keys.length - 1) {
        current[k] = decodeURIComponent(value || '');
      } else {
        current[k] = current[k] || {};
        current = current[k];
      }
    });
  });
  return params;
}

