import java.io.File;
import java.io.FileInputStream;
import java.io.FileOutputStream;
import java.io.IOException;
import java.util.zip.ZipEntry;
import java.util.zip.ZipInputStream;

public class ZipExtractor {

    /**
     * Extracts files from a ZIP archive to the specified directory.
     * If safeMode is true, it checks for existing files in the destination directory
     * that would be overwritten and prompts the user before proceeding.
     *
     * @param zipFilePath The path to the ZIP file.
     * @param destDirectory The destination directory where files will be extracted.
     * @param safeMode    If true, enables safe extraction mode.
     * @throws IOException If an I/O error occurs during extraction.
     */
    public static void extractFiles(String zipFilePath, String destDirectory, boolean safeMode) throws IOException {
        File destDir = new File(destDirectory);
        if (!destDir.exists()) {
            destDir.mkdir();
        }
        try (ZipInputStream zipIn = new ZipInputStream(new FileInputStream(zipFilePath))) {
            ZipEntry entry = zipIn.getNextEntry();
            while (entry != null) {
                String filePath = destDirectory + File.separator + entry.getName();
                if (!entry.isDirectory()) {
                    extractFile(zipIn, filePath, safeMode, destDir);
                } else {
                    File dir = new File(filePath);
                    dir.mkdir();
                }
                zipIn.closeEntry();
                entry = zipIn.getNextEntry();
            }
        }
    }

    private static void extractFile(ZipInputStream zipIn, String filePath, boolean safeMode, File destDir) throws IOException {
        File destFile = new File(filePath);
        if (safeMode && destFile.exists()) {
            String response = JOptionPane.showInputDialog("File " + destFile.getName() + " already exists. Overwrite? (y/n)");
            if (!"y".equalsIgnoreCase(response)) {
                return;
            }
        }
        try (FileOutputStream fos = new FileOutputStream(destFile)) {
            byte[] bytesIn = new byte[4096];
            int read = 0;
            while ((read = zipIn.read(bytesIn)) != -1) {
                fos.write(bytesIn, 0, read);
            }
        }
