		final Path modulePath = external ? LEnv.PATH_EXT_MODS : LEnv.PATH_MODS;

		for ( final Path file : Files.newDirectoryStream( extractPath ) ) {
			final Path target = modulePath.resolve( file.getFileName() );

			if ( Files.exists( target ) )
				Files.delete( target );

			Files.move( file, target );
		}

		// Delete temp folder
		LUtils.deletePath( tempPath );

		// Update module info
		module.setVersion( module.getVersion() + ( repair ? " (repair)" : " (update)" ) );
		module.setArchiveFile( null );
		module.setArchiveSize( 0 );

		if ( module == modules.getLauncherMod() ) {
			// Launcher update requires restart, show RESTART action while updating the launcher
			launcherFrame.setProceedText( "<html><h2>RE_START</h2></html>" );
		}

		LEnv.LOGGER.info( "Update complete." );
		launcherFrame.setStatus( StatusType.READY, "Update complete." );
	} catch ( final Exception e ) {
		LEnv.LOGGER.error( "Could not update module: " + e.getMessage() );
		launcherFrame.setStatus( StatusType.ERROR, "Could not update module: " + e.getMessage() );
	}
}

