    if (r < 0) {
        syslog(LOG_ERR, "%s: could find characteristic: %s", __FUNCTION__, uuid);
        sd_bus_error_free(&error);
        return -LB_ERROR_UNSPECIFIED;
    }

    r = sd_bus_call_method(lb_ctx->bus, BLUEZ_DEST, ble_char_new->char_path,
                           BLUEZ_GATT_CHARACTERISTICS, "StartNotify", &error, NULL, NULL);
    if (r < 0) {
        syslog(LOG_ERR, "%s: sd_bus_call_method StartNotify on device %s failed with error: %s",
               __FUNCTION__, ble_char_new->char_path, error.message);
        sd_bus_error_free(&error);
        return -LB_ERROR_SD_BUS_CALL_FAIL;
    }

    snprintf(match, sizeof(match), "type='signal',interface='org.bluez.GattCharacteristic1',path='%s'", ble_char_new->char_path);
    r = sd_bus_match_signal(lb_ctx->bus, &ble_char_new->match, match, callback, userdata);
    if (r < 0) {
        syslog(LOG_ERR, "%s: sd_bus_match_signal on device %s failed with error: %s",
               __FUNCTION__, ble_char_new->char_path, strerror(-r));
        sd_bus_error_free(&error);
        return -LB_ERROR_SD_BUS_MATCH_FAIL;
    }

    ble_char_new->read_callback = callback;
    ble_char_new->read_userdata = userdata;

    return 0;
}
